namespace SiteInspector.Models;

public class Site
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Name { get; set; } = string.Empty;
    public string Address { get; set; } = string.Empty;
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}

namespace SiteInspector.Models;

public class Inspection
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string SiteId { get; set; } = string.Empty;
    public string InspectorName { get; set; } = string.Empty;
    public DateTime InspectionDate { get; set; } = DateTime.UtcNow;
    public string Notes { get; set; } = string.Empty;
    public InspectionStatus Status { get; set; } = InspectionStatus.InProgress;
    public List<ChecklistItem> ChecklistItems { get; set; } = new();
    public List<Photo> Photos { get; set; } = new();
    public bool IsSynced { get; set; }
    public DateTime LastModified { get; set; } = DateTime.UtcNow;
}

public enum InspectionStatus
{
    InProgress,
    Completed,
    Failed
}

namespace SiteInspector.Models;

public class ChecklistItem
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public CheckResult Result { get; set; } = CheckResult.NotChecked;
    public string Notes { get; set; } = string.Empty;
    public DateTime? CheckedAt { get; set; }
}

public enum CheckResult
{
    NotChecked,
    Pass,
    Fail,
    NotApplicable
}

namespace SiteInspector.Models;

public class Photo
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string FileName { get; set; } = string.Empty;
    public string DataUrl { get; set; } = string.Empty;
    public string Caption { get; set; } = string.Empty;
    public DateTime TakenAt { get; set; } = DateTime.UtcNow;
}

namespace SiteInspector.Models;

public static class ChecklistTemplate
{
    public static List<ChecklistItem> GetDefaultChecklist() => new()
    {
        // Fall Protection
        new() { Category = "Fall Protection", Description = "Guardrails installed on open edges above 6 feet" },
        new() { Category = "Fall Protection", Description = "Floor openings covered or guarded" },
        new() { Category = "Fall Protection", Description = "Safety nets in place where required" },
        new() { Category = "Fall Protection", Description = "Personal fall arrest systems available and inspected" },

        // Scaffolding
        new() { Category = "Scaffolding", Description = "Scaffold erected on stable foundation" },
        new() { Category = "Scaffolding", Description = "Planking fully decked and secured" },
        new() { Category = "Scaffolding", Description = "Access ladders provided" },
        new() { Category = "Scaffolding", Description = "Scaffold tagged and inspected" },

        // Electrical
        new() { Category = "Electrical", Description = "GFCI protection on all temporary circuits" },
        new() { Category = "Electrical", Description = "Extension cords in good condition" },
        new() { Category = "Electrical", Description = "Electrical panels accessible and labeled" },
        new() { Category = "Electrical", Description = "Lockout/tagout procedures posted" },

        // Housekeeping
        new() { Category = "Housekeeping", Description = "Walkways clear of debris and tripping hazards" },
        new() { Category = "Housekeeping", Description = "Materials properly stacked and stored" },
        new() { Category = "Housekeeping", Description = "Waste containers available and not overflowing" },
        new() { Category = "Housekeeping", Description = "Adequate lighting in work areas" },

        // PPE
        new() { Category = "PPE", Description = "Hard hats worn in designated areas" },
        new() { Category = "PPE", Description = "Safety glasses/goggles available" },
        new() { Category = "PPE", Description = "High-visibility vests worn where required" },
        new() { Category = "PPE", Description = "Appropriate footwear worn by all workers" },

        // Fire Safety
        new() { Category = "Fire Safety", Description = "Fire extinguishers charged and accessible" },
        new() { Category = "Fire Safety", Description = "Hot work permits obtained where needed" },
        new() { Category = "Fire Safety", Description = "Flammable materials stored properly" },
        new() { Category = "Fire Safety", Description = "Emergency exits clear and marked" },

        // Excavation
        new() { Category = "Excavation", Description = "Excavations properly sloped or shored" },
        new() { Category = "Excavation", Description = "Spoil piles at least 2 feet from edge" },
        new() { Category = "Excavation", Description = "Utilities located and marked" },
        new() { Category = "Excavation", Description = "Means of egress within 25 feet of workers" },
    };
}

