// IndexedDB wrapper for SiteInspector offline storage
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (event) => {
            const database = event.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (event) => { db = event.target.result; resolve(db); };
        request.onerror = (event) => reject(event.target.error);
    });
}

window.indexedDbStorage = {
    initialize: async function () {
        await openDb();
        return true;
    },

    putItem: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(item);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function (storeName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(key);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(request.result || []);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function (storeName, indexName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(key);
            request.onsuccess = () => resolve(request.result || []);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function (storeName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(key);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedInspections: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readonly');
            const index = tx.objectStore('inspections').index('isSynced');
            const request = index.getAll(false);
            request.onsuccess = () => resolve(request.result || []);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

// Connectivity detection
window.connectivityService = {
    isOnline: function () {
        return navigator.onLine;
    },

    registerOnlineHandler: function (dotNetRef) {
        window.addEventListener('online', () => {
            dotNetRef.invokeMethodAsync('OnConnectivityChanged', true);
        });
        window.addEventListener('offline', () => {
            dotNetRef.invokeMethodAsync('OnConnectivityChanged', false);
        });
    }
};

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class LocalStorageService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        await _js.InvokeVoidAsync("indexedDbStorage.initialize");
    }

    // Sites
    public async Task<List<Site>> GetAllSitesAsync()
    {
        var results = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllItems", "sites");
        return Deserialize<List<Site>>(results);
    }

    public async Task<Site?> GetSiteAsync(string id)
    {
        var result = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "sites", id);
        return result.HasValue ? Deserialize<Site>(result.Value) : null;
    }

    public async Task SaveSiteAsync(Site site)
    {
        var data = SerializeToObject(site);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "sites", data);
    }

    public async Task DeleteSiteAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbStorage.deleteItem", "sites", id);
    }

    // Inspections
    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var results = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllItems", "inspections");
        return Deserialize<List<Inspection>>(results);
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var results = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getItemsByIndex", "inspections", "siteId", siteId);
        return Deserialize<List<Inspection>>(results);
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var result = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "inspections", id);
        return result.HasValue ? Deserialize<Inspection>(result.Value) : null;
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        inspection.LastModified = DateTime.UtcNow;
        var data = SerializeToObject(inspection);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "inspections", data);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbStorage.deleteItem", "inspections", id);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var results = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getUnsyncedInspections");
        return Deserialize<List<Inspection>>(results);
    }

    public async Task MarkAsSyncedAsync(string inspectionId)
    {
        var inspection = await GetInspectionAsync(inspectionId);
        if (inspection != null)
        {
            inspection.IsSynced = true;
            await SaveInspectionAsync(inspection);
        }
    }

    private static T Deserialize<T>(JsonElement element)
    {
        return JsonSerializer.Deserialize<T>(element.GetRawText(), JsonOptions) ?? default!;
    }

    private static object SerializeToObject<T>(T item)
    {
        var json = JsonSerializer.Serialize(item, JsonOptions);
        return JsonSerializer.Deserialize<object>(json, JsonOptions)!;
    }
}

using Microsoft.JSInterop;

namespace SiteInspector.Services;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;

    public bool IsOnline { get; private set; }
    public event Action<bool>? ConnectivityChanged;

    public ConnectivityService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        IsOnline = await _js.InvokeAsync<bool>("connectivityService.isOnline");
        _dotNetRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivityService.registerOnlineHandler", _dotNetRef);
    }

    [JSInvokable]
    public Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        ConnectivityChanged?.Invoke(isOnline);
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
        await ValueTask.CompletedTask;
    }
}

using System.Net.Http.Json;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService
{
    private readonly LocalStorageService _storage;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private bool _isSyncing;

    public event Action<string>? SyncStatusChanged;
    public int PendingSyncCount { get; private set; }

    public SyncService(LocalStorageService storage, ConnectivityService connectivity, HttpClient http)
    {
        _storage = storage;
        _connectivity = connectivity;
        _http = http;
        _connectivity.ConnectivityChanged += OnConnectivityChanged;
    }

    public async Task UpdatePendingCountAsync()
    {
        var unsynced = await _storage.GetUnsyncedInspectionsAsync();
        PendingSyncCount = unsynced.Count;
    }

    private async void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
        {
            await SyncAsync();
        }
    }

    public async Task SyncAsync()
    {
