using System.Net.Http.Json;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService
{
    private readonly LocalStorageService _storage;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private bool _isSyncing;

    public event Action<string>? SyncStatusChanged;
    public int PendingSyncCount { get; private set; }

    public SyncService(LocalStorageService storage, ConnectivityService connectivity, HttpClient http)
    {
        _storage = storage;
        _connectivity = connectivity;
        _http = http;
        _connectivity.ConnectivityChanged += OnConnectivityChanged;
    }

    public async Task UpdatePendingCountAsync()
    {
        var unsynced = await _storage.GetUnsyncedInspectionsAsync();
        PendingSyncCount = unsynced.Count;
    }

    private async void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
        {
            await SyncAsync();
        }
    }

    public async Task SyncAsync()
    {
        if (_isSyncing || !_connectivity.IsOnline) return;

        _isSyncing = true;
        SyncStatusChanged?.Invoke("Syncing...");

        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();

            foreach (var inspection in unsynced)
            {
                try
                {
                    // Attempt to post to server API
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkAsSyncedAsync(inspection.Id);
                    }
                }
                catch (HttpRequestException)
                {
                    // Server unreachable, will retry on next sync
                    break;
                }
            }

            await UpdatePendingCountAsync();
            SyncStatusChanged?.Invoke(PendingSyncCount > 0 ? $"{PendingSyncCount} pending" : "All synced");
        }
        catch (Exception ex)
        {
            SyncStatusChanged?.Invoke($"Sync error: {ex.Message}");
        }
        finally
        {
            _isSyncing = false;
        }
    }
}

