@inherits LayoutComponentBase
@inject ConnectivityService Connectivity
@inject SyncService Sync

<div class="app-container">
    <header class="app-header">
        <div class="header-content">
            <a href="/" class="header-title">
                <span class="header-icon">🏗️</span>
                <span>Site Inspector</span>
            </a>
            <div class="sync-status @(Connectivity.IsOnline ? "online" : "offline")">
                <span class="status-dot"></span>
                <span class="status-text">@_syncStatus</span>
            </div>
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

@code {
    private string _syncStatus = "Checking...";

    protected override async Task OnInitializedAsync()
    {
        Connectivity.ConnectivityChanged += OnConnectivityChanged;
        Sync.SyncStatusChanged += OnSyncStatusChanged;
        _syncStatus = Connectivity.IsOnline ? "Online" : "Offline";
        await Sync.UpdatePendingCountAsync();
        if (Sync.PendingSyncCount > 0)
        {
            _syncStatus = Connectivity.IsOnline ? "Online" : $"{Sync.PendingSyncCount} pending sync";
        }
    }

    private void OnConnectivityChanged(bool isOnline)
    {
        _syncStatus = isOnline ? "Online - syncing..." : "Offline";
        InvokeAsync(StateHasChanged);
    }

    private void OnSyncStatusChanged(string status)
    {
        _syncStatus = status;
        InvokeAsync(StateHasChanged);
    }
}

@page "/"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Sites - Site Inspector</PageTitle>

<div class="page-header">
    <h1>Construction Sites</h1>
    <button class="btn-primary" @onclick="ShowAddSite">+ Add Site</button>
</div>

@if (_showAddForm)
{
    <div class="card add-form">
        <div class="form-group">
            <label>Site Name</label>
            <input @bind="_newSiteName" @bind:event="oninput" placeholder="e.g. Downtown Tower Phase 2" class="input" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input @bind="_newSiteAddress" @bind:event="oninput" placeholder="123 Main St" class="input" />
        </div>
        <div class="form-actions">
            <button class="btn-secondary" @onclick="CancelAdd">Cancel</button>
            <button class="btn-primary" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Save</button>
        </div>
    </div>
}

@if (_sites == null)
{
    <div class="loading">Loading sites...</div>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <span class="empty-icon">🏗️</span>
        <p>No construction sites yet.</p>
        <p>Tap <strong>+ Add Site</strong> to get started.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="card site-card" @onclick="() => NavigateToSite(site.Id)">
                <div class="site-card-content">
                    <h3>@site.Name</h3>
                    <p class="site-address">@site.Address</p>
                    <p class="site-meta">@_inspectionCounts.GetValueOrDefault(site.Id, 0) inspection(s)</p>
                </div>
                <span class="chevron">›</span>
            </div>
        }
    </div>
}

@code {
    private List<Site>? _sites;
    private Dictionary<string, int> _inspectionCounts = new();
    private bool _showAddForm;
    private string _newSiteName = string.Empty;
    private string _newSiteAddress = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await LoadSites();
    }

    private async Task LoadSites()
    {
        _sites = await Storage.GetAllSitesAsync();
        foreach (var site in _sites)
        {
            var inspections = await Storage.GetInspectionsForSiteAsync(site.Id);
            _inspectionCounts[site.Id] = inspections.Count;
        }
    }

    private void ShowAddSite() => _showAddForm = true;
    private void CancelAdd() { _showAddForm = false; _newSiteName = ""; _newSiteAddress = ""; }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;
        var site = new Site { Name = _newSiteName.Trim(), Address = _newSiteAddress.Trim() };
        await Storage.SaveSiteAsync(site);
        _showAddForm = false;
        _newSiteName = "";
        _newSiteAddress = "";
        await LoadSites();
    }

    private void NavigateToSite(string siteId) => Nav.NavigateTo($"/site/{siteId}");
}

@page "/site/{SiteId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Site Details - Site Inspector</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>@(_site?.Name ?? "Loading...")</h1>
</div>

@if (_site != null)
{
    <div class="site-detail-header">
        <p class="site-address">📍 @_site.Address</p>
        <button class="btn-primary btn-large" @onclick="StartNewInspection">
            + New Inspection
        </button>
    </div>

    <h2 class="section-title">Inspection History</h2>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <span class="empty-icon">📋</span>
            <p>No inspections yet for this site.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections.OrderByDescending(i => i.InspectionDate))
            {
                <div class="card inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                    <div class="inspection-card-header">
                        <span class="inspection-date">@inspection.InspectionDate.ToString("MMM dd, yyyy HH:mm")</span>
                        <span class="status-badge @inspection.Status.ToString().ToLower()">
                            @inspection.Status
                        </span>
                    </div>
                    <div class="inspection-card-body">
                        <span class="inspector-name">👷 @(string.IsNullOrEmpty(inspection.InspectorName) ? "Unknown" : inspection.InspectorName)</span>
                        <div class="inspection-stats">
                            @{
                                var passed = inspection.ChecklistItems.Count(c => c.Result == CheckResult.Pass);
                                var failed = inspection.ChecklistItems.Count(c => c.Result == CheckResult.Fail);
                                var total = inspection.ChecklistItems.Count;
                            }
                            <span class="stat pass">✓ @passed</span>
                            <span class="stat fail">✗ @failed</span>
                            <span class="stat total">/@total</span>
                            @if (inspection.Photos.Count > 0)
                            {
                                <span class="stat photos">📷 @inspection.Photos.Count</span>
                            }
                        </div>
                    </div>
                    @if (!inspection.IsSynced)
                    {
                        <span class="sync-pending-badge">⏳ Not synced</span>
                    }
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private Site? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        _site = await Storage.GetSiteAsync(SiteId);
        _inspections = await Storage.GetInspectionsForSiteAsync(SiteId);
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            ChecklistItems = ChecklistTemplate.GetDefaultChecklist()
        };
        await Storage.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private void OpenInspection(string id) => Nav.NavigateTo($"/inspection/{id}");
}

@page "/inspection/{InspectionId}"
@inject LocalStorageService Storage
@inject SyncService Sync
@inject NavigationManager Nav

<PageTitle>Inspection - Site Inspector</PageTitle>

@if (_inspection == null)
{
    <div class="loading">Loading inspection...</div>
}
else
{
    <div class="page-header">
        <button class="btn-back" @onclick="GoBack">← Back</button>
        <h1>Inspection</h1>
        <span class="status-badge @_inspection.Status.ToString().ToLower()">@_inspection.Status</span>
    </div>

    <!-- Inspector info -->
    <div class="card inspector-section">
        <div class="form-group">
            <label>Inspector Name</label>
            <input class="input" @bind="_inspection.InspectorName" @bind:event="oninput"
                   @onfocusout="SaveInspection" placeholder="Your name" />
        </div>
        <div class="form-group">
            <label>Date</label>
            <span class="date-display">@_inspection.InspectionDate.ToString("MMM dd, yyyy HH:mm")</span>
        </div>
    </div>

    <!-- Tab navigation -->
    <div class="tab-nav">
        <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
            Checklist (@_inspection.ChecklistItems.Count(i => i.Result != CheckResult.NotChecked)/@_inspection.ChecklistItems.Count)
        </button>
        <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
            Photos (@_inspection.Photos.Count)
        </button>
        <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
            Notes
        </button>
    </div>

    <!-- Checklist Tab -->
    @if (_activeTab == "checklist")
    {
        <div class="checklist-container">
            @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
            {
                <div class="checklist-category">
                    <h3 class="category-title">@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @item.Result.ToString().ToLower()">
                            <div class="checklist-item-main">
                                <span class="checklist-desc">@item.Description</span>
                                <div class="checklist-buttons">
                                    <button class="check-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                                    <button class="check-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                                    <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                                </div>
                            </div>
                            @if (item.Result == CheckResult.Fail)
                            {
                                <div class="checklist-item-notes">
                                    <input class="input input-sm" placeholder="Add note about failure..."
                                           @bind="item.Notes" @bind:event="oninput" @onfocusout="SaveInspection" />
                                </div>
                            }
                        </div>
                    }
                </div>
            }
        </div>
    }

    <!-- Photos Tab -->
    @if (_activeTab == "photos")
    {
        <div class="photos-container">
            <label class="btn-primary photo-upload-btn">
                📷 Take / Add Photo
                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" style="display:none" />
            </label>

            @if (_inspection.Photos.Count == 0)
            {
                <div class="empty-state">
                    <span class="empty-icon">📷</span>
                    <p>No photos attached yet.</p>
                </div>
            }
            else
            {
                <div class="photo-grid">
                    @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                    {
                        <div class="photo-card">
                            <img src="@photo.DataUrl" alt="@photo.Caption" class="photo-thumbnail" />
                            <div class="photo-info">
                                <input class="input input-sm" placeholder="Add caption..."
                                       @bind="photo.Caption" @bind:event="oninput" @onfocusout="SaveInspection" />
                                <span class="photo-time">@photo.TakenAt.ToString("HH:mm")</span>
                                <button class="btn-danger-sm" @onclick="() => RemovePhoto(photo)">Remove</button>
                            </div>
                        </div>
                    }
                </div>
            }
        </div>
    }

    <!-- Notes Tab -->
    @if (_activeTab == "notes")
    {
        <div class="notes-container">
            <div class="form-group">
                <label>General Notes</label>
                <textarea class="input textarea" rows="8" placeholder="Add observations, concerns, follow-up items..."
                          @bind="_inspection.Notes" @bind:event="oninput" @onfocusout="SaveInspection"></textarea>
            </div>
        </div>
    }

    <!-- Action bar -->
    <div class="action-bar">
        @if (_inspection.Status == InspectionStatus.InProgress)
        {
            <button class="btn-success btn-large" @onclick="CompleteInspection">
                ✓ Complete Inspection
            </button>
        }
        else
        {
            <button class="btn-secondary" @onclick="ReopenInspection">
                Reopen Inspection
            </button>
        }
    </div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private string _siteId = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(InspectionId);
        if (_inspection != null)
        {
            _siteId = _inspection.SiteId;
        }
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        item.CheckedAt = DateTime.UtcNow;
        await SaveInspection();
    }

    private async Task SaveInspection()
    {
        if (_inspection == null) return;
        _inspection.IsSynced = false;
        await Storage.SaveInspectionAsync(_inspection);
        await Sync.UpdatePendingCountAsync();
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        const long maxSize = 10 * 1024 * 1024; // 10MB
        var file = e.File;
        if (file == null) return;

        // Resize for mobile storage efficiency
        var resized = await file.RequestImageFileAsync("image/jpeg", 1200, 1200);
        using var stream = resized.OpenReadStream(maxSize);
        using var ms = new MemoryStream();
        await stream.CopyToAsync(ms);
        var base64 = Convert.ToBase64String(ms.ToArray());

        var photo = new Photo
        {
            FileName = file.Name,
            DataUrl = $"data:image/jpeg;base64,{base64}",
            TakenAt = DateTime.UtcNow
        };

        _inspection!.Photos.Add(photo);
        await SaveInspection();
    }

    private async Task RemovePhoto(Photo photo)
    {
        _inspection!.Photos.Remove(photo);
        await SaveInspection();
    }

    private async Task CompleteInspection()
    {
        _inspection!.Status = InspectionStatus.Completed;
        await SaveInspection();
        _ = Sync.SyncAsync();
    }

    private async Task ReopenInspection()
    {
        _inspection!.Status = InspectionStatus.InProgress;
        await SaveInspection();
    }

    private void GoBack() => Nav.NavigateTo($"/site/{_siteId}");
}

