@code {
    private string _syncStatus = "Checking...";

    protected override async Task OnInitializedAsync()
    {
        Connectivity.ConnectivityChanged += OnConnectivityChanged;
        Sync.SyncStatusChanged += OnSyncStatusChanged;
        _syncStatus = Connectivity.IsOnline ? "Online" : "Offline";
        await Sync.UpdatePendingCountAsync();
        if (Sync.PendingSyncCount > 0)
        {
            _syncStatus = Connectivity.IsOnline ? "Online" : $"{Sync.PendingSyncCount} pending sync";
        }
    }

    private void OnConnectivityChanged(bool isOnline)
    {
        _syncStatus = isOnline ? "Online - syncing..." : "Offline";
        InvokeAsync(StateHasChanged);
    }

    private void OnSyncStatusChanged(string status)
    {
        _syncStatus = status;
        InvokeAsync(StateHasChanged);
    }
}

