@page "/"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Sites - Site Inspector</PageTitle>

<div class="page-header">
    <h1>Construction Sites</h1>
    <button class="btn-primary" @onclick="ShowAddSite">+ Add Site</button>
</div>

@if (_showAddForm)
{
    <div class="card add-form">
        <div class="form-group">
            <label>Site Name</label>
            <input @bind="_newSiteName" @bind:event="oninput" placeholder="e.g. Downtown Tower Phase 2" class="input" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input @bind="_newSiteAddress" @bind:event="oninput" placeholder="123 Main St" class="input" />
        </div>
        <div class="form-actions">
            <button class="btn-secondary" @onclick="CancelAdd">Cancel</button>
            <button class="btn-primary" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Save</button>
        </div>
    </div>
}

@if (_sites == null)
{
    <div class="loading">Loading sites...</div>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <span class="empty-icon">🏗️</span>
        <p>No construction sites yet.</p>
        <p>Tap <strong>+ Add Site</strong> to get started.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="card site-card" @onclick="() => NavigateToSite(site.Id)">
                <div class="site-card-content">
                    <h3>@site.Name</h3>
                    <p class="site-address">@site.Address</p>
                    <p class="site-meta">@_inspectionCounts.GetValueOrDefault(site.Id, 0) inspection(s)</p>
                </div>
                <span class="chevron">›</span>
            </div>
        }
    </div>
}

@code {
    private List<Site>? _sites;
    private Dictionary<string, int> _inspectionCounts = new();
    private bool _showAddForm;
    private string _newSiteName = string.Empty;
    private string _newSiteAddress = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await LoadSites();
    }

    private async Task LoadSites()
    {
        _sites = await Storage.GetAllSitesAsync();
        foreach (var site in _sites)
        {
            var inspections = await Storage.GetInspectionsForSiteAsync(site.Id);
            _inspectionCounts[site.Id] = inspections.Count;
        }
    }

    private void ShowAddSite() => _showAddForm = true;
    private void CancelAdd() { _showAddForm = false; _newSiteName = ""; _newSiteAddress = ""; }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;
        var site = new Site { Name = _newSiteName.Trim(), Address = _newSiteAddress.Trim() };
        await Storage.SaveSiteAsync(site);
        _showAddForm = false;
        _newSiteName = "";
        _newSiteAddress = "";
        await LoadSites();
    }

    private void NavigateToSite(string siteId) => Nav.NavigateTo($"/site/{siteId}");
}

