@page "/site/{SiteId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Site Details - Site Inspector</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>@(_site?.Name ?? "Loading...")</h1>
</div>

@if (_site != null)
{
    <div class="site-detail-header">
        <p class="site-address">📍 @_site.Address</p>
        <button class="btn-primary btn-large" @onclick="StartNewInspection">
            + New Inspection
        </button>
    </div>

    <h2 class="section-title">Inspection History</h2>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <span class="empty-icon">📋</span>
            <p>No inspections yet for this site.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections.OrderByDescending(i => i.InspectionDate))
            {
                <div class="card inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                    <div class="inspection-card-header">
                        <span class="inspection-date">@inspection.InspectionDate.ToString("MMM dd, yyyy HH:mm")</span>
                        <span class="status-badge @inspection.Status.ToString().ToLower()">
                            @inspection.Status
                        </span>
                    </div>
                    <div class="inspection-card-body">
                        <span class="inspector-name">👷 @(string.IsNullOrEmpty(inspection.InspectorName) ? "Unknown" : inspection.InspectorName)</span>
                        <div class="inspection-stats">
                            @{
                                var passed = inspection.ChecklistItems.Count(c => c.Result == CheckResult.Pass);
                                var failed = inspection.ChecklistItems.Count(c => c.Result == CheckResult.Fail);
                                var total = inspection.ChecklistItems.Count;
                            }
                            <span class="stat pass">✓ @passed</span>
                            <span class="stat fail">✗ @failed</span>
                            <span class="stat total">/@total</span>
                            @if (inspection.Photos.Count > 0)
                            {
                                <span class="stat photos">📷 @inspection.Photos.Count</span>
                            }
                        </div>
                    </div>
                    @if (!inspection.IsSynced)
                    {
                        <span class="sync-pending-badge">⏳ Not synced</span>
                    }
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private Site? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        _site = await Storage.GetSiteAsync(SiteId);
        _inspections = await Storage.GetInspectionsForSiteAsync(SiteId);
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            ChecklistItems = ChecklistTemplate.GetDefaultChecklist()
        };
        await Storage.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private void OpenInspection(string id) => Nav.NavigateTo($"/inspection/{id}");
}

