+                                           @bind="item.Notes" @bind:event="oninput" @onfocusout="SaveInspection" />
+                                </div>
+                            }
+                        </div>
+                    }
+                </div>
+            }
+        </div>
+    }
+
+    <!-- Photos Tab -->
+    @if (_activeTab == "photos")
+    {
+        <div class="photos-container">
+            <label class="btn-primary photo-upload-btn">
+                📷 Take / Add Photo
+                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" style="display:none" />
+            </label>
+
+            @if (_inspection.Photos.Count == 0)
+            {
+                <div class="empty-state">
+                    <span class="empty-icon">📷</span>
+                    <p>No photos attached yet.</p>
+                </div>
+            }
+            else
+            {
+                <div class="photo-grid">
+                    @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
+                    {
+                        <div class="photo-card">
+                            <img src="@photo.DataUrl" alt="@photo.Caption" class="photo-thumbnail" />
+                            <div class="photo-info">
+                                <input class="input input-sm" placeholder="Add caption..."
+                                       @bind="photo.Caption" @bind:event="oninput" @onfocusout="SaveInspection" />
+                                <span class="photo-time">@photo.TakenAt.ToString("HH:mm")</span>
+                                <button class="btn-danger-sm" @onclick="() => RemovePhoto(photo)">Remove</button>
+                            </div>
+                        </div>
+                    }
+                </div>
+            }
+        </div>
+    }
+
+    <!-- Notes Tab -->
+    @if (_activeTab == "notes")
+    {
+        <div class="notes-container">
+            <div class="form-group">
+                <label>General Notes</label>
+                <textarea class="input textarea" rows="8" placeholder="Add observations, concerns, follow-up items..."
+                          @bind="_inspection.Notes" @bind:event="oninput" @onfocusout="SaveInspection"></textarea>
+            </div>
+        </div>
+    }
+
+    <!-- Action bar -->
+    <div class="action-bar">
+        @if (_inspection.Status == InspectionStatus.InProgress)
+        {
+            <button class="btn-success btn-large" @onclick="CompleteInspection">
+                ✓ Complete Inspection
+            </button>
+        }
+        else
+        {
+            <button class="btn-secondary" @onclick="ReopenInspection">
+                Reopen Inspection
+            </button>
+        }
+    </div>
+}
+
+@code {
+    [Parameter] public string InspectionId { get; set; } = string.Empty;
+
+    private Inspection? _inspection;
+    private string _activeTab = "checklist";
+    private string _siteId = string.Empty;
+
+    protected override async Task OnInitializedAsync()
+    {
+        _inspection = await Storage.GetInspectionAsync(InspectionId);
+        if (_inspection != null)
+        {
+            _siteId = _inspection.SiteId;
+        }
+    }
+
+    private async Task SetResult(ChecklistItem item, CheckResult result)
+    {
+        item.Result = result;
+        item.CheckedAt = DateTime.UtcNow;
+        await SaveInspection();
+    }
+
+    private async Task SaveInspection()
+    {
+        if (_inspection == null) return;
+        _inspection.IsSynced = false;
+        await Storage.SaveInspectionAsync(_inspection);
+        await Sync.UpdatePendingCountAsync();
+    }
+
+    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
+    {
+        const long maxSize = 10 * 1024 * 1024; // 10MB
+        var file = e.File;
+        if (file == null) return;
+
+        // Resize for mobile storage efficiency
+        var resized = await file.RequestImageFileAsync("image/jpeg", 1200, 1200);
+        using var stream = resized.OpenReadStream(maxSize);
+        using var ms = new MemoryStream();
+        await stream.CopyToAsync(ms);
+        var base64 = Convert.ToBase64String(ms.ToArray());
+
+        var photo = new Photo
+        {
+            FileName = file.Name,
+            DataUrl = $"data:image/jpeg;base64,{base64}",
+            TakenAt = DateTime.UtcNow
+        };
+
+        _inspection!.Photos.Add(photo);
+        await SaveInspection();
+    }
+
+    private async Task RemovePhoto(Photo photo)
+    {
+        _inspection!.Photos.Remove(photo);
+        await SaveInspection();
+    }
+
+    private async Task CompleteInspection()
+    {
+        _inspection!.Status = InspectionStatus.Completed;
+        await SaveInspection();
+        _ = Sync.SyncAsync();
+    }
+
+    private async Task ReopenInspection()
+    {
+        _inspection!.Status = InspectionStatus.InProgress;
+        await SaveInspection();
+    }
+
+    private void GoBack() => Nav.NavigateTo($"/site/{_siteId}");
+}
+

