+    display: flex;
+    align-items: center;
+    cursor: pointer;
+    transition: transform 0.1s;
+    touch-action: manipulation;
+}
+.site-card:active { transform: scale(0.98); }
+.site-card-content { flex: 1; }
+.site-card h3 { margin: 0 0 0.2rem; font-size: 1.05rem; }
+.site-address { color: var(--color-text-secondary); margin: 0; font-size: 0.85rem; }
+.site-meta { color: var(--color-text-secondary); margin: 0.3rem 0 0; font-size: 0.8rem; }
+.chevron { font-size: 1.5rem; color: var(--color-text-secondary); }
+
+/* Site detail */
+.site-detail-header {
+    margin-bottom: 1.5rem;
+}
+.site-detail-header .site-address {
+    margin-bottom: 1rem;
+    font-size: 0.95rem;
+}
+.section-title {
+    font-size: 1.1rem;
+    color: var(--color-text-secondary);
+    margin: 1.5rem 0 0.75rem;
+    text-transform: uppercase;
+    font-weight: 600;
+    letter-spacing: 0.5px;
+}
+
+/* Inspection cards */
+.inspection-card {
+    cursor: pointer;
+    touch-action: manipulation;
+}
+.inspection-card:active { transform: scale(0.98); }
+.inspection-card-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    margin-bottom: 0.5rem;
+}
+.inspection-date { font-weight: 600; font-size: 0.9rem; }
+.inspection-card-body {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+}
+.inspector-name { font-size: 0.85rem; color: var(--color-text-secondary); }
+.inspection-stats {
+    display: flex;
+    gap: 0.5rem;
+    font-size: 0.8rem;
+    font-weight: 600;
+}
+.stat.pass { color: var(--color-success); }
+.stat.fail { color: var(--color-danger); }
+.stat.total { color: var(--color-text-secondary); }
+.stat.photos { color: var(--color-primary); }
+
+/* Status badges */
+.status-badge {
+    font-size: 0.7rem;
+    font-weight: 600;
+    padding: 0.2rem 0.5rem;
+    border-radius: 12px;
+    text-transform: uppercase;
+}
+.status-badge.inprogress { background: #fff3cd; color: #856404; }
+.status-badge.completed { background: #d4edda; color: #155724; }
+.status-badge.failed { background: #f8d7da; color: #721c24; }
+
+.sync-pending-badge {
+    display: inline-block;
+    margin-top: 0.5rem;
+    font-size: 0.75rem;
+    color: var(--color-warning);
+}
+
+/* Forms */
+.form-group {
+    margin-bottom: 0.75rem;
+}
+.form-group label {
+    display: block;
+    font-size: 0.8rem;
+    font-weight: 600;
+    color: var(--color-text-secondary);
+    margin-bottom: 0.3rem;
+    text-transform: uppercase;
+    letter-spacing: 0.3px;
+}
+
+.input {
+    width: 100%;
+    padding: 0.7rem;
+    border: 1px solid var(--color-border);
+    border-radius: 8px;
+    font-size: 1rem;
+    background: var(--color-bg);
+    color: var(--color-text);
+    transition: border-color 0.2s;
+}
+.input:focus {
+    outline: none;
+    border-color: var(--color-primary);
+}
+.input-sm { padding: 0.5rem; font-size: 0.85rem; }
+.textarea { resize: vertical; min-height: 120px; }
+
+.form-actions {
+    display: flex;
+    gap: 0.75rem;
+    justify-content: flex-end;
+    margin-top: 0.75rem;
+}
+
+.date-display {
+    font-size: 0.95rem;
+    color: var(--color-text);
+}
+
+/* Tabs */
+.tab-nav {
+    display: flex;
+    gap: 0;
+    margin-bottom: 1rem;
+    border-bottom: 2px solid var(--color-border);
+    overflow-x: auto;
+    -webkit-overflow-scrolling: touch;
+}
+.tab {
+    flex: 1;
+    padding: 0.7rem 0.5rem;
+    border: none;
+    background: none;
+    font-size: 0.85rem;
+    font-weight: 600;
+    color: var(--color-text-secondary);
+    cursor: pointer;
+    border-bottom: 2px solid transparent;
+    margin-bottom: -2px;
+    white-space: nowrap;
+    touch-action: manipulation;
+}
+.tab.active {
+    color: var(--color-primary);
+    border-bottom-color: var(--color-primary);
+}
+
+/* Checklist */
+.checklist-container {
+    margin-bottom: 2rem;
+}
+.checklist-category {
+    margin-bottom: 1.25rem;
+}
+.category-title {
+    font-size: 0.85rem;
+    font-weight: 700;
+    color: var(--color-primary);
+    text-transform: uppercase;
+    letter-spacing: 0.5px;
+    margin: 0 0 0.5rem;
+    padding-bottom: 0.3rem;
+    border-bottom: 1px solid var(--color-border);
+}
+
+.checklist-item {
+    background: var(--color-surface);
+    border: 1px solid var(--color-border);
+    border-radius: 8px;
+    margin-bottom: 0.4rem;
+    padding: 0.6rem 0.75rem;
+    transition: background-color 0.15s;
+}
+.checklist-item.pass { background: var(--color-pass); border-color: #b4e7c2; }
+.checklist-item.fail { background: var(--color-fail); border-color: #f9c0c7; }
+.checklist-item.notapplicable { background: var(--color-na); border-color: #d1d5da; }
+
+.checklist-item-main {
+    display: flex;
+    align-items: center;
+    gap: 0.5rem;
+}
+.checklist-desc {
+    flex: 1;
+    font-size: 0.88rem;
+    line-height: 1.3;
+}
+
+.checklist-buttons {
+    display: flex;
+    gap: 0.3rem;
+    flex-shrink: 0;
+}
+
+.check-btn {
+    width: 36px;
+    height: 36px;
+    border-radius: 50%;
+    border: 2px solid var(--color-border);
+    background: var(--color-surface);
+    font-size: 0.9rem;
+    font-weight: bold;
+    cursor: pointer;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    transition: transform 0.1s, background-color 0.1s;
+    touch-action: manipulation;
+}
+.check-btn:active { transform: scale(0.9); }
+.check-btn.pass { border-color: var(--color-success); color: var(--color-success); }
+.check-btn.pass.selected { background: var(--color-success); color: white; }
+.check-btn.fail { border-color: var(--color-danger); color: var(--color-danger); }
+.check-btn.fail.selected { background: var(--color-danger); color: white; }
+.check-btn.na { border-color: #6a737d; color: #6a737d; font-size: 0.65rem; }
+.check-btn.na.selected { background: #6a737d; color: white; }
+
+.checklist-item-notes {
+    margin-top: 0.5rem;
+}
+
+/* Photos */
+.photos-container { margin-bottom: 2rem; }
+.photo-upload-btn {
+    display: block;
+    text-align: center;
+    margin-bottom: 1rem;
+    padding: 1rem;
+    font-size: 1rem;
+    cursor: pointer;
+}
+
+.photo-grid {
+    display: grid;
+    grid-template-columns: 1fr;
+    gap: 0.75rem;
+}
+
+.photo-card {
+    background: var(--color-surface);
+    border-radius: var(--radius);
+    overflow: hidden;
+    box-shadow: var(--shadow);
+    border: 1px solid var(--color-border);
+}
+.photo-thumbnail {
+    width: 100%;
+    height: 200px;
+    object-fit: cover;
+}
+.photo-info {
+    padding: 0.75rem;
+    display: flex;
+    align-items: center;
+    gap: 0.5rem;
+    flex-wrap: wrap;
+}
+.photo-time {
+    font-size: 0.75rem;
+    color: var(--color-text-secondary);
+}
+
+/* Notes */
+.notes-container { margin-bottom: 2rem; }
+
+/* Action bar */
+.action-bar {
+    position: fixed;
+    bottom: 0;
+    left: 0;
+    right: 0;
+    padding: 1rem;
+    padding-bottom: calc(1rem + var(--safe-bottom));
+    background: var(--color-surface);
+    border-top: 1px solid var(--color-border);
+    box-shadow: 0 -2px 8px rgba(0,0,0,0.08);
+    z-index: 50;
+}
+
+/* Empty states */
+.empty-state {
+    text-align: center;
+    padding: 3rem 1rem;
+    color: var(--color-text-secondary);
+}
+.empty-icon { font-size: 3rem; display: block; margin-bottom: 1rem; }
+
+.loading {
+    text-align: center;
+    padding: 2rem;
+    color: var(--color-text-secondary);
+}
+
+/* Error UI */
+#blazor-error-ui {
+    background: lightyellow;
+    bottom: 0;
+    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
+    display: none;
+    left: 0;
+    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
+    position: fixed;
+    width: 100%;
+    z-index: 1000;
+}
+#blazor-error-ui .dismiss {
+    cursor: pointer;
+    position: absolute;
+    right: 0.75rem;
+    top: 0.5rem;
+}
+
+/* Tablet breakpoint */
+@media (min-width: 768px) {
+    .photo-grid {
+        grid-template-columns: 1fr 1fr;
+    }
+    .checklist-item-main {
+        gap: 1rem;
+    }
+    .check-btn {
+        width: 42px;
+        height: 42px;
+    }
+}
+

